-- =====================================================================
-- 전체 테이블 생성 스크립트 (Oracle)
-- 원본: create_table_query.sql (ERDCloud 내보내기) 를 Oracle 용으로 정리
-- 실행: SQL Developer "스크립트 실행(F5)" 또는 SQL*Plus 에서 한 번에 실행 가능
-- 순서: (1) 테이블 + 컬럼 코멘트   (2) 외래키(FK) 제약조건
--
-- [원본 대비 주요 변경 사항]
--  - DATETIME            -> TIMESTAMP (Oracle 타입)
--  - VARCHAR(n)          -> VARCHAR2(n) 통일
--  - AUTO_INCREMENT      -> GENERATED BY DEFAULT AS IDENTITY (PK 채번)
--  - 잘못된 DEFAULT 구문 제거 (주석 텍스트가 섞여 있던 부분)
--  - ON UPDATE 제거 (MySQL 전용 구문)
--  - CLOB / TEXT -> CLOB,  CLOB / BLOB -> BLOB
--  - 코멘트 내 따옴표 이스케이프 처리
--  - 테이블명 공백 제거: QUESTION_PASSAGE, APPROVAL_MASTER/LINE/TEMPLATE
--  - 임시 테이블 제외: Untitled33, Untitled35, CopyOfUntitled
--  - CMMT_ATCH_FILE_CL.ATCH_FILE_ID 타입을 NUMBER(20)으로 통일 (FK 일치)
--
-- [검토 필요 - 원본 오류로 추정되어 합리적으로 수정함]
--  - COURSE: 자동증가 표시가 SUBJ_CL_ID 에 있었으나 PK 인 COURSE_SN 으로 이동
--  - ASSIGNMENT_BOARD: 자동증가 표시가 CLASS_SN 에 있었으나 PK 인 ASGMT_SN 으로 이동
--  - ASSIGNMENT_BOARD / COURSE_SATISFACTION / COM_CD:
--      RGTR_ID,LAST_MDFR_ID 와 REG_DT,MDFCN_DT 의 타입이 뒤바뀌어 있어 바로잡음
--  - BOARD.INQ_CNT: VARCHAR2(255) -> NUMBER(10) (조회수)
--  - TEXTBOOK.SUBJ_CD: VARCHAR2(255) -> CHAR(10) (SUBJECT.SUBJ_CD 참조)
--  - BOARD_COMMENT: 모든 컬럼이 VARCHAR2(255) 였음 -> 컬럼명에 맞는 타입으로 정정
--  - 컬럼명 정정: COURSE_PLAN."Field2 WKLY_PLAN_CN" -> WKLY_PLAN_CN
--  - QUESTION_LIST.FIELD5, POPUP.FIELD: 의미 불명 컬럼 (원본 그대로 유지, 확인 필요)
--  - CMMT_ATCH_FILE_CL.ATCH_FILE_ID: 채번 방식(시퀀스/수동) 미정 - 일반 NUMBER 컬럼
--
-- 주의: 재실행 시 "이미 사용 중인 이름" 오류가 나면 기존 테이블을 먼저 DROP 해야 합니다.
-- =====================================================================


-- =====================================================================
-- (1) 테이블 생성 + 컬럼 코멘트
-- =====================================================================

CREATE TABLE DEPARTMENT (
    DEPT_CD       CHAR(4)        NOT NULL,
    PRNT_DEPT_CD  CHAR(4)        NULL,
    DEPT_NM       VARCHAR2(100)  NULL,
    USE_YN        CHAR(1)        DEFAULT 'Y' NULL,
    INTL_TEL_NO   VARCHAR2(10)   NULL,
    RGTR_ID       VARCHAR2(20)   NULL,
    LAST_MDFR_ID  VARCHAR2(20)   NULL,
    REG_DT        TIMESTAMP      NULL,
    MDFCN_DT      TIMESTAMP      NULL,
    CONSTRAINT PK_DEPARTMENT PRIMARY KEY (DEPT_CD)
);
COMMENT ON COLUMN DEPARTMENT.DEPT_CD      IS '예: 100행정 200미디어 300강사';
COMMENT ON COLUMN DEPARTMENT.PRNT_DEPT_CD IS 'NULL이면 최상위 부서';
COMMENT ON COLUMN DEPARTMENT.USE_YN       IS 'Y:사용 / N:미사용';
COMMENT ON COLUMN DEPARTMENT.INTL_TEL_NO  IS '사무실 번호';

CREATE TABLE TEXTBOOK_HISTORY (
    INVT_HIST_SN      NUMBER(20)    GENERATED BY DEFAULT AS IDENTITY,
    TEXTBOOK_SN       NUMBER(20)    NOT NULL,
    IO_TYPE_CD        CHAR(2)       NULL,
    CHG_CNT           NUMBER(5)     NULL,
    BFR_CHG_CNT       NUMBER(5)     NULL,
    AFT_CHG_CNT       NUMBER(5)     NULL,
    REL_DUTY_TYPE_CD  CHAR(2)       NULL,
    REL_DUTY_ID       NUMBER(20)    NULL,
    PROC_DT           TIMESTAMP     DEFAULT CURRENT_TIMESTAMP NULL,
    PROC_USER_ID      VARCHAR2(20)  NULL,
    CONSTRAINT PK_TEXTBOOK_HISTORY PRIMARY KEY (INVT_HIST_SN, TEXTBOOK_SN)
);
COMMENT ON COLUMN TEXTBOOK_HISTORY.INVT_HIST_SN     IS '복합PK(1/2) 시퀀스';
COMMENT ON COLUMN TEXTBOOK_HISTORY.TEXTBOOK_SN      IS '복합PK(2/2)';
COMMENT ON COLUMN TEXTBOOK_HISTORY.IO_TYPE_CD       IS 'COM_CD 공통코드 참조';
COMMENT ON COLUMN TEXTBOOK_HISTORY.CHG_CNT          IS '입고(+) / 출고(-) 구분 저장 권장';
COMMENT ON COLUMN TEXTBOOK_HISTORY.REL_DUTY_TYPE_CD IS 'COM_CD 공통코드 참조';

CREATE TABLE COURSE (
    COURSE_SN         NUMBER(20)     GENERATED BY DEFAULT AS IDENTITY,
    SUBJ_ID           NUMBER(20)     NOT NULL,
    INSTR_USER_ID     VARCHAR2(20)   NOT NULL,
    COURSE_NM         VARCHAR2(200)  NULL,
    COURSE_EXPLN_CN   VARCHAR2(4000) NULL,
    THMB_IMG          VARCHAR2(300)  NULL,
    TOT_LRN_TIME_CNT  VARCHAR2(20)   NULL,
    OPNN_YN           CHAR(1)        DEFAULT 'Y' NULL,
    ATCH_FILE_ID      VARCHAR2(500)  NULL,
    PROD_MTHD_CD      CHAR(2)        NULL,
    RGTR_ID           VARCHAR2(20)   NULL,
    LAST_MDFR_ID      VARCHAR2(20)   NULL,
    REG_DT            TIMESTAMP      NULL,
    MDFCN_DT          TIMESTAMP      NULL,
    SUBJ_CL_ID        NUMBER(20)     NOT NULL,
    CONSTRAINT PK_COURSE PRIMARY KEY (COURSE_SN)
);
COMMENT ON COLUMN COURSE.COURSE_SN        IS '기본키(PK) · 시퀀스';
COMMENT ON COLUMN COURSE.COURSE_EXPLN_CN  IS '해당 강좌 설명 및 소개';
COMMENT ON COLUMN COURSE.TOT_LRN_TIME_CNT IS '01:12:24';
COMMENT ON COLUMN COURSE.OPNN_YN          IS '강좌 공개 여부';
COMMENT ON COLUMN COURSE.ATCH_FILE_ID     IS '공통첨부파일분류';
COMMENT ON COLUMN COURSE.PROD_MTHD_CD     IS 'COM_CD 공통코드 참조';

CREATE TABLE BOARD (
    POST_SN        NUMBER(20)     GENERATED BY DEFAULT AS IDENTITY,
    WRTR_USER_ID   VARCHAR2(20)   NOT NULL,
    BOARD_TYPE_CD  CHAR(2)        NULL,
    POST_SJ        VARCHAR2(300)  NULL,
    POST_CN        VARCHAR2(4000) NULL,
    ATCH_FILE_ID   VARCHAR2(500)  NULL,
    TOP_FIX_ORD    NUMBER(10)     NULL,
    POPUP_EXPS_YN  CHAR(1)        DEFAULT 'N' NULL,
    INQ_CNT        NUMBER(10)     NULL,
    LAST_MDFR_ID   VARCHAR2(20)   NULL,
    REG_DT         TIMESTAMP      NOT NULL,
    MDFCN_DT       TIMESTAMP      NOT NULL,
    CONSTRAINT PK_BOARD PRIMARY KEY (POST_SN)
);
COMMENT ON COLUMN BOARD.POST_SN       IS '기본키(PK) · 시퀀스';
COMMENT ON COLUMN BOARD.WRTR_USER_ID  IS 'MEMBER.USER_ID 참조';
COMMENT ON COLUMN BOARD.ATCH_FILE_ID  IS '공통첨부파일분류';
COMMENT ON COLUMN BOARD.TOP_FIX_ORD   IS 'NULL이면 일반 게시글';
COMMENT ON COLUMN BOARD.POPUP_EXPS_YN IS 'Y:팝업노출 / N:미노출';
COMMENT ON COLUMN BOARD.LAST_MDFR_ID  IS '마지막 수정자';

CREATE TABLE INSTRUCTOR_QNA (
    POST_SN       NUMBER(20)  NOT NULL,
    QSTN_TYPE_CD  CHAR(2)     NULL,
    COURSE_SN     NUMBER(20)  NULL,
    ANSW_YN       CHAR(1)     DEFAULT 'N' NULL,
    SECR_YN       CHAR(1)     DEFAULT 'N' NULL,
    CONSTRAINT PK_INSTRUCTOR_QNA PRIMARY KEY (POST_SN)
);
COMMENT ON COLUMN INSTRUCTOR_QNA.QSTN_TYPE_CD IS 'COM_CD 참조';
COMMENT ON COLUMN INSTRUCTOR_QNA.COURSE_SN    IS 'COURSE.COURSE_SN 참조';
COMMENT ON COLUMN INSTRUCTOR_QNA.ANSW_YN      IS 'Y:답변완료/N:답변대기';
COMMENT ON COLUMN INSTRUCTOR_QNA.SECR_YN      IS 'Y:비밀 / N:공개';

CREATE TABLE EMP_ATTENDANCE (
    ATNDNC_SN           NUMBER(20)    GENERATED BY DEFAULT AS IDENTITY,
    ATNDNC_USER_ID      VARCHAR2(20)  NOT NULL,
    ATNDNC_TYPE_CD      CHAR(2)       NULL,
    ATNDNC_REG_DT       TIMESTAMP     NOT NULL,
    ATNDNC_REG_IP_ADDR  VARCHAR2(15)  NULL,
    CONSTRAINT PK_EMP_ATTENDANCE PRIMARY KEY (ATNDNC_SN)
);
COMMENT ON COLUMN EMP_ATTENDANCE.ATNDNC_SN          IS '기본키(PK) · 자동증가';
COMMENT ON COLUMN EMP_ATTENDANCE.ATNDNC_USER_ID     IS 'MEMBER.USER_ID 참조 (FK)';
COMMENT ON COLUMN EMP_ATTENDANCE.ATNDNC_TYPE_CD     IS 'COM_CD (CL_CODE=''ATNDNC'') 참조';
COMMENT ON COLUMN EMP_ATTENDANCE.ATNDNC_REG_IP_ADDR IS '근태 등록 단말 IP 출퇴근 위조 방지 로그용';

CREATE TABLE QUESTION_PASSAGE (
    PASS_SN       NUMBER(20)     GENERATED BY DEFAULT AS IDENTITY,
    SUBJ_ID       NUMBER(20)     NULL,
    PASS_CN       VARCHAR2(4000) NULL,
    STAT_CD       CHAR(2)        DEFAULT '01' NULL,
    RGTR_ID       VARCHAR2(20)   NULL,
    LAST_MDFR_ID  VARCHAR2(20)   NULL,
    REG_DT        TIMESTAMP      NULL,
    MDFCN_DT      TIMESTAMP      NULL,
    CONSTRAINT PK_QUESTION_PASSAGE PRIMARY KEY (PASS_SN)
);
COMMENT ON COLUMN QUESTION_PASSAGE.PASS_SN IS '시퀀스';
COMMENT ON COLUMN QUESTION_PASSAGE.SUBJ_ID IS 'SUBJ 테이블 참조';
COMMENT ON COLUMN QUESTION_PASSAGE.STAT_CD IS '문제생성시에만 검사';

CREATE TABLE MEMBER (
    USER_ID          VARCHAR2(20)   NOT NULL,
    USER_ENPSWD      VARCHAR2(256)  NOT NULL,
    USER_NAME        VARCHAR2(100)  NOT NULL,
    USER_ENRRNO      VARCHAR2(256)  NULL,
    USER_GNDR_CD     CHAR(1)        NULL,
    USER_BRDT        DATE           NULL,
    JOIN_DT          TIMESTAMP      DEFAULT CURRENT_TIMESTAMP NOT NULL,
    USER_TELNO       VARCHAR2(11)   NULL,
    USER_EMAIL_ADDR  VARCHAR2(300)  NULL,
    USER_ZIP         VARCHAR2(10)   NULL,
    USER_ADDR        VARCHAR2(255)  NULL,
    USER_DADDR       VARCHAR2(255)  NULL,
    USER_PROFILE     VARCHAR2(500)  NULL,
    REG_DATE         TIMESTAMP      DEFAULT CURRENT_TIMESTAMP NOT NULL,
    MOD_DATE         TIMESTAMP      DEFAULT CURRENT_TIMESTAMP NOT NULL,
    ENABLE           VARCHAR2(1)    DEFAULT '1' NULL,
    CONSTRAINT PK_MEMBER PRIMARY KEY (USER_ID)
);
COMMENT ON COLUMN MEMBER.USER_ID      IS '기본키 (PK)';
COMMENT ON COLUMN MEMBER.USER_ENPSWD  IS '암호화된 비번';
COMMENT ON COLUMN MEMBER.USER_NAME    IS '사용자명';
COMMENT ON COLUMN MEMBER.USER_ENRRNO  IS 'AES-256 암호화 필수';
COMMENT ON COLUMN MEMBER.USER_GNDR_CD IS 'M:남성 F:여성 U:미확인';
COMMENT ON COLUMN MEMBER.JOIN_DT      IS '가입 시각';
COMMENT ON COLUMN MEMBER.USER_TELNO   IS '(9)99-(9)999-9999 형식';
COMMENT ON COLUMN MEMBER.USER_PROFILE IS '이미지 URL/경로';
COMMENT ON COLUMN MEMBER.REG_DATE     IS '데이터 생성 시점';
COMMENT ON COLUMN MEMBER.MOD_DATE     IS '데이터 수정 시점';

CREATE TABLE EXAM_QUESTION (
    EXAM_SN    NUMBER(20)  NOT NULL,
    QSTN_SN    NUMBER(20)  NOT NULL,
    QSTN_ORDR  NUMBER(10)  NULL,
    CONSTRAINT PK_EXAM_QUESTION PRIMARY KEY (EXAM_SN, QSTN_SN)
);

CREATE TABLE MEMBER_ROLE (
    USER_ROLE_CD  VARCHAR2(20)   NOT NULL,
    AUTHRT_NM     VARCHAR2(100)  NULL,
    MDFR_ID       VARCHAR2(20)   NULL,
    MDFCN_DT      TIMESTAMP      NULL,
    RGTR_ID       VARCHAR2(20)   NULL,
    REG_DT        TIMESTAMP      NOT NULL,
    LAST_MDFR_ID  VARCHAR2(20)   NULL,
    CONSTRAINT PK_MEMBER_ROLE PRIMARY KEY (USER_ROLE_CD)
);
COMMENT ON COLUMN MEMBER_ROLE.USER_ROLE_CD IS '기본키(PK)';
COMMENT ON COLUMN MEMBER_ROLE.MDFR_ID      IS '마지막 수정한 사용자 ID';
COMMENT ON COLUMN MEMBER_ROLE.MDFCN_DT     IS '데이터 수정 시점';
COMMENT ON COLUMN MEMBER_ROLE.RGTR_ID      IS '처음 등록한 사용자 ID';
COMMENT ON COLUMN MEMBER_ROLE.REG_DT       IS '데이터 최초 생성 시점';
COMMENT ON COLUMN MEMBER_ROLE.LAST_MDFR_ID IS '가장 최근 수정자 ID';

CREATE TABLE JOB_GRADE (
    JBGR_CD           CHAR(4)       NOT NULL,
    JBGR_NM           VARCHAR2(50)  NULL,
    SORT_ORD          NUMBER(10)    NULL,
    USE_YN            CHAR(1)       NULL,
    BASE_ANN_LV_DAYS  NUMBER(3)     NULL,
    RGTR_ID           VARCHAR2(20)  NULL,
    LAST_MDFR_ID      VARCHAR2(20)  NULL,
    REG_DT            TIMESTAMP     NULL,
    MDFCN_DT          TIMESTAMP     NULL,
    CONSTRAINT PK_JOB_GRADE PRIMARY KEY (JBGR_CD)
);
COMMENT ON COLUMN JOB_GRADE.USE_YN           IS 'Y:사용 / N:미사용';
COMMENT ON COLUMN JOB_GRADE.BASE_ANN_LV_DAYS IS '직급별 기본 부여 일수 · DEFAULT 15';

CREATE TABLE MESSAGE_ROOM_PARTICIPANT (
    PART_SN          NUMBER(20)    GENERATED BY DEFAULT AS IDENTITY,
    ROOM_SN          NUMBER(20)    NOT NULL,
    PART_USER_ID     VARCHAR2(20)  NOT NULL,
    JOIN_DT          TIMESTAMP     DEFAULT CURRENT_TIMESTAMP NOT NULL,
    EXIT_DT          TIMESTAMP     NULL,
    NOTI_YN          CHAR(1)       DEFAULT 'Y' NULL,
    LST_READ_MSG_SN  NUMBER(20)    NULL,
    CONSTRAINT PK_MESSAGE_ROOM_PARTICIPANT PRIMARY KEY (PART_SN, ROOM_SN)
);
COMMENT ON COLUMN MESSAGE_ROOM_PARTICIPANT.PART_SN         IS '기본키(PK) · 시퀀스';
COMMENT ON COLUMN MESSAGE_ROOM_PARTICIPANT.PART_USER_ID    IS '채팅방 구성원';
COMMENT ON COLUMN MESSAGE_ROOM_PARTICIPANT.JOIN_DT         IS '대화방 입장 일시';
COMMENT ON COLUMN MESSAGE_ROOM_PARTICIPANT.EXIT_DT         IS '그룹 채팅 나가기 시 기록';
COMMENT ON COLUMN MESSAGE_ROOM_PARTICIPANT.NOTI_YN         IS 'Y:알림ON / N:알림OFF';
COMMENT ON COLUMN MESSAGE_ROOM_PARTICIPANT.LST_READ_MSG_SN IS '안읽은 메시지 수 계산 기준 읽을 때마다 갱신';

CREATE TABLE EMPLOYEE_INFO (
    USER_ID       VARCHAR2(20)   NOT NULL,
    DEPT_CD       CHAR(4)        NOT NULL,
    JBGR_CD       CHAR(4)        NOT NULL,
    JOIN_YMD      TIMESTAMP      NULL,
    RETMT_YMD     TIMESTAMP      NULL,
    EMPL_STAT_CD  CHAR(2)        NULL,
    ATCH_FILE_ID  VARCHAR2(500)  NULL,
    CHRG_DUTY_CN  VARCHAR2(4000) NULL,
    RGTR_ID       VARCHAR2(20)   NULL,
    LAST_MDFR_ID  VARCHAR2(20)   NULL,
    REG_DT        TIMESTAMP      NULL,
    MDFCN_DT      TIMESTAMP      NULL,
    CONSTRAINT PK_EMPLOYEE_INFO PRIMARY KEY (USER_ID)
);
COMMENT ON COLUMN EMPLOYEE_INFO.USER_ID      IS '기본키(PK)';
COMMENT ON COLUMN EMPLOYEE_INFO.DEPT_CD      IS '부서 테이블 참조(FK)';
COMMENT ON COLUMN EMPLOYEE_INFO.JBGR_CD      IS '직급 테이블 참조(FK)';
COMMENT ON COLUMN EMPLOYEE_INFO.JOIN_YMD     IS '실제 출근 시작 날짜';
COMMENT ON COLUMN EMPLOYEE_INFO.EMPL_STAT_CD IS '재직,휴직,퇴사 등 상태값 (01:재직 02:휴직 03:퇴사)';
COMMENT ON COLUMN EMPLOYEE_INFO.ATCH_FILE_ID IS '공통첨부파일분류';

CREATE TABLE CARD_PAY_HIST (
    CARD_PAY_SN        NUMBER(20)     GENERATED BY DEFAULT AS IDENTITY,
    PAY_HIST_SN        NUMBER(20)     NOT NULL,
    NICE_TID           VARCHAR2(30)   NOT NULL,
    ORDER_ID           VARCHAR2(100)  NULL,
    APRVL_NO           VARCHAR2(10)   NULL,
    PAY_AMT            NUMBER(15)     NOT NULL,
    BALANCE_AMT        NUMBER(15)     NULL,
    GOODS_NM           VARCHAR2(100)  NULL,
    PAY_MTHD_CD        VARCHAR2(10)   NULL,
    CARD_CD            VARCHAR2(4)    NULL,
    CARD_NM            VARCHAR2(20)   NULL,
    CARD_NO_MASK       VARCHAR2(20)   NULL,
    CARD_QUOTA         NUMBER(2)      NULL,
    IS_INTRST_FREE_YN  CHAR(1)        NULL,
    CARD_TYPE_CD       VARCHAR2(10)   NULL,
    CAN_PART_CNCL_YN   CHAR(1)        NULL,
    RECEIPT_URL_ADDR   VARCHAR2(320)  NULL,
    PAID_AT            TIMESTAMP      NULL,
    REG_DT             TIMESTAMP      DEFAULT CURRENT_TIMESTAMP NOT NULL,
    CONSTRAINT PK_CARD_PAY_HIST PRIMARY KEY (CARD_PAY_SN)
);
COMMENT ON COLUMN CARD_PAY_HIST.CARD_PAY_SN       IS '기본키(PK) · 시퀀스';
COMMENT ON COLUMN CARD_PAY_HIST.NICE_TID          IS '[NicePay]tid 취소 API URL 경로로 사용';
COMMENT ON COLUMN CARD_PAY_HIST.ORDER_ID          IS '[NicePay]orderId';
COMMENT ON COLUMN CARD_PAY_HIST.APRVL_NO          IS '[NicePay]approveNo 카드사 승인번호 · 환불/분쟁 처리';
COMMENT ON COLUMN CARD_PAY_HIST.PAY_AMT           IS '[NicePay]amount';
COMMENT ON COLUMN CARD_PAY_HIST.BALANCE_AMT       IS '[NicePay]balanceAmt 현재 취소 가능한 금액';
COMMENT ON COLUMN CARD_PAY_HIST.GOODS_NM          IS '[NicePay]goodsName';
COMMENT ON COLUMN CARD_PAY_HIST.PAY_MTHD_CD       IS '[NicePay]payMethod';
COMMENT ON COLUMN CARD_PAY_HIST.CARD_CD           IS '[NicePay]card.cardCode';
COMMENT ON COLUMN CARD_PAY_HIST.CARD_NM           IS '[NicePay]card.cardName 예: 삼성';
COMMENT ON COLUMN CARD_PAY_HIST.CARD_NO_MASK      IS '[NicePay]card.cardNum 마스킹된 카드번호 저장';
COMMENT ON COLUMN CARD_PAY_HIST.CARD_QUOTA        IS '[NicePay]card.cardQuota 0=일시불, 1~12=할부';
COMMENT ON COLUMN CARD_PAY_HIST.IS_INTRST_FREE_YN IS '[NicePay]card.isInterestFree';
COMMENT ON COLUMN CARD_PAY_HIST.CARD_TYPE_CD      IS '[NicePay]card.cardType NicePay 원문 그대로 저장';
COMMENT ON COLUMN CARD_PAY_HIST.CAN_PART_CNCL_YN  IS '[NicePay]card.canPartCancel';
COMMENT ON COLUMN CARD_PAY_HIST.RECEIPT_URL_ADDR  IS '[NicePay]receiptUrl 사용자 영수증 발급 링크';
COMMENT ON COLUMN CARD_PAY_HIST.PAID_AT           IS '[NicePay]paidAt';

CREATE TABLE DATA_ROOM (
    POST_SN      NUMBER(20)  NOT NULL,
    DATA_CTG     CHAR(2)     NULL,
    EXPS_ORD     NUMBER(10)  NULL,
    ACCS_LMT_CD  CHAR(2)     NULL,
    CONSTRAINT PK_DATA_ROOM PRIMARY KEY (POST_SN)
);
COMMENT ON COLUMN DATA_ROOM.POST_SN     IS '기본키(PK) · 시퀀스';
COMMENT ON COLUMN DATA_ROOM.DATA_CTG    IS '강의노트, 참고서적 등';
COMMENT ON COLUMN DATA_ROOM.ACCS_LMT_CD IS '전체공개, 수강생 전용 등';

CREATE TABLE COURSE_SATISFACTION (
    STSFN_SN            NUMBER(20)     GENERATED BY DEFAULT AS IDENTITY,
    COURSE_SN           NUMBER(20)     NOT NULL,
    STD_USER_ID         VARCHAR2(20)   NOT NULL,
    COURSE_STSFN_SCORE  NUMBER(1)      NULL,
    INSTR_STSFN_SCORE   NUMBER(1)      NULL,
    ETC_SCORE           NUMBER(1)      NULL,
    REVW_CN             VARCHAR2(4000) NULL,
    PUB_YN              CHAR(1)        NULL,
    RGTR_ID             VARCHAR2(20)   NULL,
    LAST_MDFR_ID        VARCHAR2(20)   NULL,
    REG_DT              TIMESTAMP      NOT NULL,
    MDFCN_DT            TIMESTAMP      NOT NULL,
    CONSTRAINT PK_COURSE_SATISFACTION PRIMARY KEY (STSFN_SN, COURSE_SN)
);
COMMENT ON COLUMN COURSE_SATISFACTION.STSFN_SN           IS '기본키(PK) · 자동증가';
COMMENT ON COLUMN COURSE_SATISFACTION.STD_USER_ID        IS 'MEMBER.USER_ID 참조';
COMMENT ON COLUMN COURSE_SATISFACTION.COURSE_STSFN_SCORE IS '1~5 (1점 척도 기준)';
COMMENT ON COLUMN COURSE_SATISFACTION.INSTR_STSFN_SCORE  IS '1~5 (1점 척도 기준)';
COMMENT ON COLUMN COURSE_SATISFACTION.ETC_SCORE          IS '1~5 (1점 척도 기준)';
