COMMENT ON COLUMN COM_CD.COM_CD  IS '기본키(PK) 복합키';
COMMENT ON COLUMN COM_CD.CL_CODE IS '기본키(PK) 복합키';
COMMENT ON COLUMN COM_CD.USE_YN  IS 'DEFAULT ''Y'' 권장';

