COMMENT ON COLUMN APPROVAL_TEMPLATE.USE_YN       IS 'DEFAULT ''Y'' 권장';
COMMENT ON COLUMN APPROVAL_TEMPLATE.ATCH_FILE_ID IS '공통첨부파일분류';

CREATE TABLE PAY_CNCL_HIST (
    CNCL_SN             NUMBER(20)     GENERATED BY DEFAULT AS IDENTITY,
    PAY_HIST_SN         NUMBER(20)     NOT NULL,
    PG_TID              VARCHAR2(30)   NULL,
    KAKAO_AID           VARCHAR2(30)   NULL,
    CNCL_AMT            NUMBER(15)     NOT NULL,
    CNCL_TAX_FREE_AMT   NUMBER(15)     NULL,
    CNCL_VAT_AMT        NUMBER(15)     NULL,
    ACCUM_CNCL_AMT      NUMBER(15)     NULL,
    AVAIL_CNCL_AMT      NUMBER(15)     NULL,
    PAY_STAT_CD         VARCHAR2(30)   NULL,
    CNCL_DT             TIMESTAMP      NULL,
    CNCL_RQSTR_USER_ID  VARCHAR2(20)   NULL,
    CNCL_RSN_CN         VARCHAR2(4000) NULL,
    PG_ERR_CD           VARCHAR2(10)   NULL,
    REG_DT              TIMESTAMP      NOT NULL,
    CONSTRAINT PK_PAY_CNCL_HIST PRIMARY KEY (CNCL_SN, PAY_HIST_SN)
);
COMMENT ON COLUMN PAY_CNCL_HIST.CNCL_SN            IS '기본키(PK) · 시퀀스';
COMMENT ON COLUMN PAY_CNCL_HIST.PG_TID             IS '[kakao/nicepay]tid (응답)';
COMMENT ON COLUMN PAY_CNCL_HIST.KAKAO_AID          IS '[KakaoPay]aid (응답)';
COMMENT ON COLUMN PAY_CNCL_HIST.CNCL_AMT           IS '[KakaoPay]approved_cancel_amount.total';
COMMENT ON COLUMN PAY_CNCL_HIST.CNCL_TAX_FREE_AMT  IS '[KakaoPay]approved_cancel_amount.tax_free';
COMMENT ON COLUMN PAY_CNCL_HIST.CNCL_VAT_AMT       IS '[KakaoPay]approved_cancel_amount.vat';
COMMENT ON COLUMN PAY_CNCL_HIST.ACCUM_CNCL_AMT     IS '[KakaoPay]canceled_amount.total 부분취소 누적 추적용';
COMMENT ON COLUMN PAY_CNCL_HIST.AVAIL_CNCL_AMT     IS '[KakaoPay]cancel_available_amount.total 0이면 전체취소 완료';
COMMENT ON COLUMN PAY_CNCL_HIST.PAY_STAT_CD        IS '[KakaoPay]status (취소 후 상태)';
COMMENT ON COLUMN PAY_CNCL_HIST.CNCL_DT            IS '[KakaoPay]canceled_at';
COMMENT ON COLUMN PAY_CNCL_HIST.CNCL_RQSTR_USER_ID IS 'MEMBER.USER_ID 참조';
COMMENT ON COLUMN PAY_CNCL_HIST.CNCL_RSN_CN        IS '취소 사유 메모';
COMMENT ON COLUMN PAY_CNCL_HIST.PG_ERR_CD          IS 'Error_code 취소 실패 시 저장';

CREATE TABLE CMMT_ATCH_FILE_DTL (
