    FILE_SIZE_CNT     NUMBER(15)     NULL,
    FILE_CN           BLOB           NULL,
    REG_DT            TIMESTAMP      DEFAULT CURRENT_TIMESTAMP NULL,
    RGTR_ID           VARCHAR2(20)   NULL,
    DEL_YN            CHAR(1)        NULL,
    DEL_DT            TIMESTAMP      NULL,
    DEL_USER_ID       VARCHAR2(20)   NULL,
