    CONSTRAINT PK_CMMT_ATCH_FILE_DTL PRIMARY KEY (ATCH_FILE_DTL_SN, ATCH_FILE_ID)
);
COMMENT ON COLUMN CMMT_ATCH_FILE_DTL.ATCH_FILE_DTL_SN IS '기본키(PK) · 시퀀스';
COMMENT ON COLUMN CMMT_ATCH_FILE_DTL.FILE_EXT_NM      IS 'jpg·png·pdf·docx 등';
COMMENT ON COLUMN CMMT_ATCH_FILE_DTL.FILE_SIZE_CNT    IS '(Byte 단위)';
COMMENT ON COLUMN CMMT_ATCH_FILE_DTL.FILE_CN          IS '바이너리 또는 텍스트';
COMMENT ON COLUMN CMMT_ATCH_FILE_DTL.DEL_YN           IS 'Y : 삭제 / N : 정상';
COMMENT ON COLUMN CMMT_ATCH_FILE_DTL.DWNLD_CNT        IS '파일 다운로드 횟수 누적';

CREATE TABLE PAY_HIST (
    PAY_HIST_SN   NUMBER(20)     GENERATED BY DEFAULT AS IDENTITY,
    USER_ID       VARCHAR2(20)   NOT NULL,
    PROD_DIV_CD   CHAR(2)        NULL,
    PAY_DIV_CD    CHAR(2)        NOT NULL,
    NICE_TID      VARCHAR2(30)   NULL,
    CID           CHAR(10)       NULL,
    KAKAO_TID     VARCHAR2(20)   NULL,
    PTNR_ORD_ID   VARCHAR2(100)  NULL,
    ITEM_NM       VARCHAR2(100)  NULL,
    ITEM_CD       VARCHAR2(100)  NULL,
    ITEM_QTY      NUMBER(5)      NULL,
    PAY_TYPE_CD   VARCHAR2(2)    NULL,
    PAY_STAT_CD   VARCHAR2(30)   NULL,
    TOT_AMT       NUMBER(15)     NOT NULL,
    TAX_FREE_AMT  NUMBER(15)     NULL,
    VAT_AMT       NUMBER(15)     NULL,
    POINT_AMT     NUMBER(15)     NULL,
    DISCOUNT_AMT  NUMBER(15)     NULL,
    INSTLMT_MTH   NUMBER(2)      NULL,
    PAY_READY_DT  TIMESTAMP      NULL,
    PAY_APRVL_DT  TIMESTAMP      NULL,
    REG_DT        TIMESTAMP      DEFAULT CURRENT_TIMESTAMP NOT NULL,
    RGTR_ID       VARCHAR2(20)   NULL,
    MDFCN_DT      TIMESTAMP      DEFAULT CURRENT_TIMESTAMP NULL,
    CONSTRAINT PK_PAY_HIST PRIMARY KEY (PAY_HIST_SN)
);
COMMENT ON COLUMN PAY_HIST.PAY_HIST_SN  IS '기본키(PK) · 시퀀스';
COMMENT ON COLUMN PAY_HIST.USER_ID      IS 'MEMBER.USER_ID 참조';
COMMENT ON COLUMN PAY_HIST.PROD_DIV_CD  IS '10:교재 / 20:강의 / 30:등록비 등';
COMMENT ON COLUMN PAY_HIST.PAY_DIV_CD   IS '01:계좌이체 / 02:카드결제 / 03: 카카오페이 등';
COMMENT ON COLUMN PAY_HIST.CID          IS '[KakaoPay]cid 가맹점 코드 10자 고정';
COMMENT ON COLUMN PAY_HIST.KAKAO_TID    IS '[KakaoPay]취소 API 필수 파라미터 · 없으면 취소 불가';
COMMENT ON COLUMN PAY_HIST.PTNR_ORD_ID  IS '[KakaoPay]partner_order_id 가맹점 자체 주문번호';
COMMENT ON COLUMN PAY_HIST.ITEM_NM      IS '[KakaoPay]item_name';
COMMENT ON COLUMN PAY_HIST.ITEM_CD      IS '[KakaoPay]item_code';
COMMENT ON COLUMN PAY_HIST.ITEM_QTY     IS '[KakaoPay]quantity';
COMMENT ON COLUMN PAY_HIST.PAY_TYPE_CD  IS '[KakaoPay]payment_method_type CARD 또는 MONEY';
COMMENT ON COLUMN PAY_HIST.PAY_STAT_CD  IS '[KakaoPay]카카오페이 status 값 그대로 저장 권장';
COMMENT ON COLUMN PAY_HIST.TOT_AMT      IS '[KakaoPay]amount.total';
COMMENT ON COLUMN PAY_HIST.TAX_FREE_AMT IS '[KakaoPay]amount.tax_free';
COMMENT ON COLUMN PAY_HIST.VAT_AMT      IS '[KakaoPay]amount.vat';
COMMENT ON COLUMN PAY_HIST.POINT_AMT    IS '[KakaoPay]amount.point';
COMMENT ON COLUMN PAY_HIST.DISCOUNT_AMT IS '[KakaoPay]amount.discount';
COMMENT ON COLUMN PAY_HIST.INSTLMT_MTH  IS '[KakaoPay]Y/N -> 개월 수 / install_month';
COMMENT ON COLUMN PAY_HIST.PAY_READY_DT IS '[KakaoPay]created_at';
COMMENT ON COLUMN PAY_HIST.PAY_APRVL_DT IS '[KakaoPay]approved_at';

CREATE TABLE PARENT_JOIN_LINK (
    LINK_ID         NUMBER(20)     GENERATED BY DEFAULT AS IDENTITY,
