ALTER TABLE EXAM_QUESTION ADD CONSTRAINT FK_QUESTION_LIST_TO_EXAM_QUESTION_1
    FOREIGN KEY (QSTN_SN) REFERENCES QUESTION_LIST (QSTN_SN);

